// Nur heutige Einträge filtern und CSV erzeugen
// Format: Semikolon, UTF-8 mit BOM, CRLF — deutsches Standardformat für Excel-Kompatibilität

const heute = new Date().toLocaleDateString('de-DE', {
  timeZone: 'Europe/Berlin',
  day: '2-digit', month: '2-digit', year: 'numeric'
});

const alleEintraege = $input.all();
const heutigeEintraege = alleEintraege.filter(item => item.json['Datum'] === heute);

// CSV-Kopfzeile
const spalten = ['TN-ID', 'Name', 'Kurs-ID', 'Kurs-Name', 'Datum', 'Zeit', 'Timestamp'];

// Hilfsfunktion: Feld für CSV escapen
// Enthält das Feld Semikolon, Anführungszeichen oder Zeilenumbruch → in Anführungszeichen einschließen
function csvFeld(wert) {
  const s = String(wert ?? '');
  if (s.includes(';') || s.includes('"') || s.includes('\n') || s.includes('\r')) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
}

const zeilen = [spalten.join(';')];

for (const item of heutigeEintraege) {
  const zeile = spalten.map(sp => csvFeld(item.json[sp])).join(';');
  zeilen.push(zeile);
}

// UTF-8 BOM + CRLF-Zeilenenden
const csvInhalt = '\uFEFF' + zeilen.join('\r\n');

const dateiName = `anwesenheit_${heute.replace(/\./g, '-')}.csv`;

return [{
  json: {
    csvInhalt,
    dateiName,
    anzahl: heutigeEintraege.length,
    datum: heute
  }
}];

// CSV als Base64-Anhang vorbereiten (n8n erwartet Binary-Daten für Mail-Anhänge)
// Wir geben den CSV-Inhalt als binäres Item durch
const { csvInhalt, dateiName, anzahl, datum } = $input.first().json;

// n8n's setBinaryData für den nächsten Node
const binaryData = Buffer.from(csvInhalt, 'utf8').toString('base64');

return [{
  json: {
    dateiName,
    anzahl,
    datum,
    csvBase64: binaryData,
    betreff: `Anwesenheitsliste ${datum} – ${anzahl} Eintrag${anzahl !== 1 ? 'träge' : ''}`,
    nachricht: `Anbei die Anwesenheitsliste vom ${datum}.\n\nAnzahl Einträge: ${anzahl}\n\nDiese E-Mail wurde automatisch generiert.`
  },
  binary: {
    anhang: {
      data: binaryData,
      mimeType: 'text/csv',
      fileName: dateiName
    }
  }
}];
